fn iput(local: &str, remote: &str) {
    let status = Command::new("iput")
        .args(["-f", local, remote])
        .status()
        .expect("failed to spawn iput");
    assert!(status.success(), "iput {} {} failed", local, remote);
}

/// Returns true iff iRODS has a user with the given name.
///
/// Uses `iquest` rather than `iuserinfo` for the existence check:
/// `iuserinfo` exits with status 0 even for non-existent users (it
/// treats "user not found" as a normal informational outcome rather
/// than an error), so its exit status alone can't tell the two cases
/// apart. `iquest` runs a catalog query directly: stdout contains the
/// matched username on its own line when the user exists, and
/// `CAT_NO_ROWS_FOUND` (or similar diagnostic) when it doesn't.
fn user_exists(name: &str) -> bool {
    Command::new("iquest")
        .args([
            "%s",
            &format!("SELECT USER_NAME WHERE USER_NAME = '{}'", name),
        ])
        .output()
        .map(|out| {
            String::from_utf8_lossy(&out.stdout)
                .lines()
                .any(|line| line.trim() == name)
        })
        .unwrap_or(false)
}

/// `imkdir -p <remote>`: create a collection (idempotent).
fn imkdir(remote: &str) {
    let status = Command::new("imkdir")
        .args(["-p", remote])
        .status()
        .expect("failed to spawn imkdir");
    assert!(status.success(), "imkdir {} failed", remote);
}

fn imeta_add(kind_flag: &str, path: &str, attr: &str, value: &str, units: Option<&str>) {
    let mut args: Vec<String> = vec![
        "add".to_string(),
        kind_flag.to_string(),
        path.to_string(),
        attr.to_string(),
        value.to_string(),
    ];
    if let Some(u) = units {
        args.push(u.to_string());
    }
    let status = Command::new("imeta")
        .args(&args)
        .status()
        .expect("failed to spawn imeta");
    assert!(status.success(), "imeta add {} {} failed", kind_flag, path);
}

